1. using System;
2. using Microsoft.VisualStudio.TestTools.UnitTesting;
3. using Store;
4. 
5. #nullable enable
6. 
7. namespace Tests;
8. 
9. [TestClass]
10. public sealed class ShoppingCartTests
11. {
12.     private ShoppingCart _sut = null!;
13. 
14.     [TestInitialize]
15.     public void Setup() => _sut = new ShoppingCart();
16. 
17.     // --- AddItem ---
18. 
19.     [TestMethod]
20.     [DataRow("SKU-001", 1, 9.99, DisplayName = "Single item")]
21.     [DataRow("SKU-002", 5, 2.50, DisplayName = "Multiple quantity")]
22.     public void AddItem_ValidInputs_DoesNotThrow(string sku, int qty, double price)
23.     {
24.         _sut.AddItem(sku, qty, (decimal)price);
25.         Assert.AreEqual((decimal)price * qty, _sut.CalculateTotal());
26.     }
27. 
28.     [TestMethod]
29.     public void AddItem_SameSkuTwice_CombinesQuantity()
30.     {
31.         _sut.AddItem("A", 2, 10m);
32.         _sut.AddItem("A", 3, 10m);
33. 
34.         // 5 items at $10
35.         Assert.AreEqual(50m, _sut.CalculateTotal());
36.     }
37. 
38.     [TestMethod]
39.     public void AddItem_NullSku_ThrowsArgumentNullException()
40.     {
41.         Assert.ThrowsException<ArgumentNullException>(() => _sut.AddItem(null!, 1, 5m));
42.     }
43. 
44.     [TestMethod]
45.     [DataRow("", DisplayName = "Empty SKU")]
46.     [DataRow("   ", DisplayName = "Whitespace SKU")]
47.     public void AddItem_EmptyOrWhitespaceSku_ThrowsArgumentException(string sku)
48.     {
49.         Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku, 1, 5m));
50.     }
51. 
52.     [TestMethod]
53.     [DataRow(0, DisplayName = "Zero quantity")]
54.     [DataRow(-1, DisplayName = "Negative quantity")]
55.     public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int qty)
56.     {
57.         Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("X", qty, 5m));
58.     }
59. 
60.     [TestMethod]
61.     public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
62.     {
63.         Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("X", 1, -1m));
64.     }
65. 
66.     // --- RemoveItem ---
67. 
68.     [TestMethod]
69.     public void RemoveItem_ExistingItem_RemovesFromCart()
70.     {
71.         _sut.AddItem("A", 1, 10m);
72.         _sut.RemoveItem("A");
73. 
74.         Assert.AreEqual(0m, _sut.CalculateTotal());
75.     }
76. 
77.     [TestMethod]
78.     public void RemoveItem_NonExistentItem_ThrowsInvalidOperationException()
79.     {
80.         Assert.ThrowsException<InvalidOperationException>(() => _sut.RemoveItem("MISSING"));
81.     }
82. 
83.     [TestMethod]
84.     public void RemoveItem_NullSku_ThrowsArgumentNullException()
85.     {
86.         Assert.ThrowsException<ArgumentNullException>(() => _sut.RemoveItem(null!));
87.     }
88. 
89.     [TestMethod]
90.     public void RemoveItem_EmptySku_ThrowsArgumentException()
91.     {
92.         Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(""));
93.     }
94. 
95.     // --- CalculateTotal ---
96. 
97.     [TestMethod]
98.     public void CalculateTotal_EmptyCart_ReturnsZero()
99.     {
100.         Assert.AreEqual(0m, _sut.CalculateTotal());
101.     }
102. 
103.     [TestMethod]
104.     public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
105.     {
106.         _sut.AddItem("A", 2, 10m);  // 20
107.         _sut.AddItem("B", 1, 5m);   // 5
108. 
109.         Assert.AreEqual(25m, _sut.CalculateTotal());
110.     }
111. 
112.     // --- ApplyCoupon ---
113. 
114.     [TestMethod]
115.     [DataRow("SAVE10", 10, DisplayName = "10% off")]
116.     [DataRow("SAVE20", 20, DisplayName = "20% off")]
117.     [DataRow("HALFOFF", 50, DisplayName = "50% off")]
118.     public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int discountPct)
119.     {
120.         _sut.AddItem("A", 1, 100m);
121.         _sut.ApplyCoupon(code);
122. 
123.         var expected = 100m - (100m * discountPct / 100m);
124.         Assert.AreEqual(expected, _sut.CalculateTotal());
125.     }
126. 
127.     [TestMethod]
